// Interfeys genişləndirmə sintaksisi
interface Point {
  x: number;
  y: number;
}

interface ThreeDPoint extends Point {
  z: number;
}

let point: ThreeDPoint = {
  x: 10,
  y: 20,
  z: 30
};

console.log(point); // { x: 10, y: 20, z: 30 }
// let invalid: ThreeDPoint = { x: 5, z: 15 }; // Xəta: y xüsusiyyəti yoxdur

// Interfeys genişləndirmə vs Tip aliasları
type Id = number | string;

interface User {
  name: string;
}

interface NamedUser extends User {
  id: Id;
}

let user: NamedUser = {
  id: 1,
  name: 'Ali'
};

console.log(user); // { id: 1, name: 'Ali' }
// let invalid: NamedUser = { name: 'Vəli' }; // Xəta: id xüsusiyyəti yoxdur

// Çoxlu miras alma
interface Contact {
  email: string;
}

interface Profile {
  username: string;
}

interface User extends Contact, Profile {
  id: number;
}

let user: User = {
  id: 1,
  email: 'ali@example.com',
  username: 'ali123'
};

console.log(user); // { id: 1, email: 'ali@example.com', username: 'ali123' }
// let invalid: User = { id: 2, email: 'veli@example.com' }; // Xəta: username yoxdur

// Opsiyonel və read-only xüsusiyyətlərlə genişləndirmə
interface Person {
  name: string;
  age?: number;
}

interface Employee extends Person {
  readonly employeeId: number;
}

let employee: Employee = {
  name: 'Ali',
  employeeId: 101
};

console.log(employee); // { name: 'Ali', employeeId: 101 }
employee.name = 'Vəli';
// employee.employeeId = 102; // Xəta: employeeId yalnız oxuna biləndir

// Funksiyalarda interfeys genişləndirmə
interface User {
  name: string;
}

interface Admin extends User {
  role: 'admin';
}

function printAdmin(admin: Admin): string {
  return `${admin.name} is ${admin.role}`;
}

let admin: Admin = { name: 'Ali', role: 'admin' };
console.log(printAdmin(admin)); // Ali is admin
// let invalid: Admin = { name: 'Vəli' }; // Xəta: role yoxdur

// Praktik nümunə
interface Product {
  id: number;
  name: string;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Phone',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900
// let invalid: DiscountedProduct = { id: 2, name: 'Laptop', discount: 0.8 }; // Xəta: price yoxdur

// Təhlükəsizlik nümunəsi
interface Person {
  name: string;
}

interface Manager extends Person {
  department: string;
}

function getManagerInfo(manager: Manager): string {
  return `${manager.name} manages ${manager.department}`;
}

let manager: Manager = { name: 'Ali', department: 'IT' };
console.log(getManagerInfo(manager)); // Ali manages IT
// let invalid: Manager = { name: 'Vəli' }; // Xəta: department yoxdur

// Səhvə yol açan nümunə
let unsafe: any = { name: 'Ali', role: 'admin' };
console.log(unsafe.name, unsafe.role); // Ali, admin, lakin tip təhlükəsizliyi yoxdur
unsafe = { name: 'Vəli' };
console.log(unsafe.name, unsafe.role); // Vəli, undefined, runtime xətası ola bilər

// Düzgün yol
interface User {
  name: string;
}

interface Admin extends User {
  role: string;
}
let admin: Admin = { name: 'Ali', role: 'admin' };
console.log(admin.name, admin.role); // Ali, admin
// let invalid: Admin = { name: 'Vəli' }; // Xəta: role yoxdur

// Real layihə ssenarisi
interface Product {
  id: number;
  name: string;
  price: number;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Phone',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900

