// Interface extending syntax
interface Point {
  x: number;
  y: number;
}

interface ThreeDPoint extends Point {
  z: number;
}

let point: ThreeDPoint = {
  x: 10,
  y: 20,
  z: 30
};

console.log(point); // { x: 10, y: 20, z: 30 }
// let invalid: ThreeDPoint = { x: 5, z: 15 }; // Error: property 'y' is missing

// Interface extending vs. Type aliases
type Id = number | string;

interface User {
  name: string;
}

interface NamedUser extends User {
  id: Id;
}

let user: NamedUser = {
  id: 1,
  name: 'Alice'
};

console.log(user); // { id: 1, name: 'Alice' }
// let invalid: NamedUser = { name: 'Bob' }; // Error: property 'id' is missing

// Multiple inheritance
interface Contact {
  email: string;
}

interface Profile {
  username: string;
}

interface User extends Contact, Profile {
  id: number;
}

let user: User = {
  id: 1,
  email: 'alice@example.com',
  username: 'alice123'
};

console.log(user); // { id: 1, email: 'alice@example.com', username: 'alice123' }
// let invalid: User = { id: 2, email: 'bob@example.com' }; // Error: username is missing

// Extending with optional and read-only properties
interface Person {
  name: string;
  age?: number;
}

interface Employee extends Person {
  readonly employeeId: number;
}

let employee: Employee = {
  name: 'Alice',
  employeeId: 101
};

console.log(employee); // { name: 'Alice', employeeId: 101 }
employee.name = 'Bob';
// employee.employeeId = 102; // Error: employeeId is read-only

// Interface extending in functions
interface User {
  name: string;
}

interface Admin extends User {
  role: 'admin';
}

function printAdmin(admin: Admin): string {
  return `${admin.name} is ${admin.role}`;
}

let admin: Admin = { name: 'Alice', role: 'admin' };
console.log(printAdmin(admin)); // Alice is admin
// let invalid: Admin = { name: 'Bob' }; // Error: role is missing

// Practical example
interface Product {
  id: number;
  name: string;
  price: number;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Phone',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900
// let invalid: DiscountedProduct = { id: 2, name: 'Laptop', discount: 0.8 }; // Error: price is missing

// Security example
interface Person {
  name: string;
}

interface Manager extends Person {
  department: string;
}

function getManagerInfo(manager: Manager): string {
  return `${manager.name} manages ${manager.department}`;
}

let manager: Manager = { name: 'Alice', department: 'IT' };
console.log(getManagerInfo(manager)); // Alice manages IT
// let invalid: Manager = { name: 'Bob' }; // Error: department is missing

// Error-prone example
let unsafe: any = { name: 'Alice', role: 'admin' };
console.log(unsafe.name, unsafe.role); // Alice, admin, but no type safety
unsafe = { name: 'Bob' };
console.log(unsafe.name, unsafe.role); // Bob, undefined, may cause runtime errors

// Correct approach
interface User {
  name: string;
}

interface Admin extends User {
  role: string;
}
let admin: Admin = { name: 'Alice', role: 'admin' };
console.log(admin.name, admin.role); // Alice, admin
// let invalid: Admin = { name: 'Bob' }; // Error: role is missing

// Real-world scenario
interface Product {
  id: number;
  name: string;
  price: number;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Phone',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900

