// Синтаксис расширения интерфейсов
interface Point {
  x: number;
  y: number;
}

interface ThreeDPoint extends Point {
  z: number;
}

let point: ThreeDPoint = {
  x: 10,
  y: 20,
  z: 30
};

console.log(point); // { x: 10, y: 20, z: 30 }
// let invalid: ThreeDPoint = { x: 5, z: 15 }; // Ошибка: отсутствует свойство 'y'

// Расширение интерфейсов против псевдонимов типов
type Id = number | string;

interface User {
  name: string;
}

interface NamedUser extends User {
  id: Id;
}

let user: NamedUser = {
  id: 1,
  name: 'Алиса'
};

console.log(user); // { id: 1, name: 'Алиса' }
// let invalid: NamedUser = { name: 'Боб' }; // Ошибка: отсутствует свойство 'id'

// Множественное наследование
interface Contact {
  email: string;
}

interface Profile {
  username: string;
}

interface User extends Contact, Profile {
  id: number;
}

let user: User = {
  id: 1,
  email: 'alice@example.com',
  username: 'alice123'
};

console.log(user); // { id: 1, email: 'alice@example.com', username: 'alice123' }
// let invalid: User = { id: 2, email: 'bob@example.com' }; // Ошибка: отсутствует username

// Расширение с необязательными и свойствами только для чтения
interface Person {
  name: string;
  age?: number;
}

interface Employee extends Person {
  readonly employeeId: number;
}

let employee: Employee = {
  name: 'Алиса',
  employeeId: 101
};

console.log(employee); // { name: 'Алиса', employeeId: 101 }
employee.name = 'Боб';
// employee.employeeId = 102; // Ошибка: employeeId только для чтения

// Расширение интерфейсов в функциях
interface User {
  name: string;
}

interface Admin extends User {
  role: 'admin';
}

function printAdmin(admin: Admin): string {
  return `${admin.name} является ${admin.role}`;
}

let admin: Admin = { name: 'Алиса', role: 'admin' };
console.log(printAdmin(admin)); // Алиса является admin
// let invalid: Admin = { name: 'Боб' }; // Ошибка: отсутствует role

// Практический пример
interface Product {
  id: number;
  name: string;
  price: number;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Телефон',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900
// let invalid: DiscountedProduct = { id: 2, name: 'Ноутбук', discount: 0.8 }; // Ошибка: отсутствует price

// Пример безопасности
interface Person {
  name: string;
}

interface Manager extends Person {
  department: string;
}

function getManagerInfo(manager: Manager): string {
  return `${manager.name} управляет ${manager.department}`;
}

let manager: Manager = { name: 'Алиса', department: 'IT' };
console.log(getManagerInfo(manager)); // Алиса управляет IT
// let invalid: Manager = { name: 'Боб' }; // Ошибка: отсутствует department

// Пример, вызывающий ошибку
let unsafe: any = { name: 'Алиса', role: 'admin' };
console.log(unsafe.name, unsafe.role); // Алиса, admin, но без безопасности типов
unsafe = { name: 'Боб' };
console.log(unsafe.name, unsafe.role); // Боб, undefined, может вызвать ошибки во время выполнения

// Правильный подход
interface User {
  name: string;
}

interface Admin extends User {
  role: string;
}
let admin: Admin = { name: 'Алиса', role: 'admin' };
console.log(admin.name, admin.role); // Алиса, admin
// let invalid: Admin = { name: 'Боб' }; // Ошибка: отсутствует role

// Реальный сценарий
interface Product {
  id: number;
  name: string;
  price: number;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Телефон',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900

